mapper.select:
SELECT m.id, m.major_name, m.major_code, m.org_unit_id, o.unit_name as org_unit_name, m.description, m.status, CASE m.status WHEN 1 THEN '启用' WHEN 0 THEN '禁用' ELSE '未知' END as status_name, m.created_at, m.updated_at FROM majors m LEFT JOIN org_units o ON m.org_unit_id = o.id WHERE m.deleted = 0
AND m.major_name LIKE CONCAT('%', #{params.majorName}, '%')
AND m.major_code LIKE CONCAT('%', #{params.majorCode}, '%')
AND m.org_unit_id = #{params.orgUnitId}
AND m.status = #{params.status}
ORDER BY m.created_at DESC
